def compute_score() -> tuple[str, float]:
    from ppteval.verify.ppt.verifier import ScreenshotsUnavailableError
    # Find slide 4 screenshots
    original_slide_4 = None
    modified_slide_4 = None

    for screenshot in original_ppt_screenshots:
        if screenshot.slide_number == 4:
            original_slide_4 = screenshot
            break

    for screenshot in modified_ppt_screenshots:
        if screenshot.slide_number == 4:
            modified_slide_4 = screenshot
            break

    if not original_slide_4 or not modified_slide_4:
        raise ScreenshotsUnavailableError("Could not find slide 4 screenshots for comparison; flagging task for verification retry.")

    prompt = """Compare these two PowerPoint slides (original vs modified). 

    Task: The user was supposed to change the color tone of a figure on this slide so that its background looks light blue.

    Please analyze if the color tone of the figure's background has been changed to light blue in the modified version.
    Respond with:
    - PASS if a figure's background has been successfully changed to light blue
    - FAIL if no figure background was changed to light blue or if the change is inappropriate
    - Include a brief explanation of what you observe"""

    try:
        response = vlm_call(prompt, [original_slide_4.image_path, modified_slide_4.image_path], temperature=0.3)

        if "PASS" in response.upper():
            return f"Figure background successfully changed to light blue: {response}", 1.0
        else:
            return f"Figure background not properly changed to light blue: {response}", 0.0

    except Exception as e:
        return f"Error in visual comparison: {str(e)}", 0.0

def compute_score() -> tuple[str, float]:
    from pptx import Presentation

    try:
        original_prs = Presentation(original_ppt_path)
        modified_prs = Presentation(modified_ppt_path)

        # Check if number of slides changed
        if len(original_prs.slides) != len(modified_prs.slides):
            return f"Number of slides changed from {len(original_prs.slides)} to {len(modified_prs.slides)}", 0.0

        # Check slides other than slide 4 (index 3)
        changes_found = []
        total_other_slides = 0

        for i, (orig_slide, mod_slide) in enumerate(zip(original_prs.slides, modified_prs.slides)):
            if i == 3:  # Skip slide 4 (0-indexed)
                continue

            total_other_slides += 1

            # Basic check for slide modifications
            if len(orig_slide.shapes) != len(mod_slide.shapes):
                changes_found.append(f"Slide {i+1} shape count changed")

        # Check PPTDiff for animations/transitions on other slides
        for anim in ppt_diff.added_animations + ppt_diff.removed_animations:
            slide_num = int(anim.slide_id.split('_')[-1]) if '_' in anim.slide_id else 0
            if slide_num != 4:
                changes_found.append(f"Animation change on slide {slide_num}")

        for transition in ppt_diff.added_transitions + ppt_diff.removed_transitions:
            slide_num = int(transition.slide_id.split('_')[-1]) if '_' in transition.slide_id else 0
            if slide_num != 4:
                changes_found.append(f"Transition change on slide {slide_num}")

        if changes_found:
            return f"Extraneous changes detected: {'; '.join(changes_found[:3])}", 0.5

        return f"No extraneous changes detected on {total_other_slides} other slides", 1.0

    except Exception as e:
        return f"Error checking other slides: {str(e)}", 0.5

def compute_score() -> tuple[str, float]:
    from pptx import Presentation

    try:
        original_prs = Presentation(original_ppt_path)
        modified_prs = Presentation(modified_ppt_path)

        if len(original_prs.slides) < 4 or len(modified_prs.slides) < 4:
            return "Slide 4 not available for comparison", 0.5

        orig_slide_4 = original_prs.slides[3]
        mod_slide_4 = modified_prs.slides[3]

        # Check if number of shapes changed by more than 1 (allowing for one figure color change)
        if len(orig_slide_4.shapes) + 1 < len(mod_slide_4.shapes):
            return f"Number of shapes on slide 4 changed from {len(orig_slide_4.shapes)} to {len(mod_slide_4.shapes)}", 0.3

        # Check for major structural changes
        major_changes = []

        # Check if slide title changed (if it exists)
        orig_title = None
        mod_title = None

        for shape in orig_slide_4.shapes:
            if shape.has_text_frame and hasattr(shape, 'placeholder_format'):
                if shape.placeholder_format and shape.placeholder_format.type == 1:  # Title placeholder
                    orig_title = shape.text
                    break

        for shape in mod_slide_4.shapes:
            if shape.has_text_frame and hasattr(shape, 'placeholder_format'):
                if shape.placeholder_format and shape.placeholder_format.type == 1:  # Title placeholder
                    mod_title = shape.text
                    break

        if orig_title != mod_title:
            major_changes.append("Slide title changed")

        if major_changes:
            return f"Unnecessary changes detected: {'; '.join(major_changes)}", 0.5

        return "Only minimal changes detected on slide 4, likely just the target figure color", 1.0

    except Exception as e:
        return f"Error checking slide 4 modifications: {str(e)}", 0.5
